    this.moves++;

    // Prevent infinite loops
    if (this.moves > 2500) {
      return "right";
    }

    // Check for gold in current cell or neighbors
    if (cell.type === 3) {
      this.goldFound = true;
      this.goldPos = {level: cell.level};
      // If we're at the gold and high enough, we're done
      if (cell.level >= 8) {
        return "pickup";
      }
    }

    // Check neighbors for gold
    const neighbors = [
      {dir: "left", data: cell.left},
      {dir: "up", data: cell.up}, 
      {dir: "right", data: cell.right},
      {dir: "down", data: cell.down}
    ];

    for (let neighbor of neighbors) {
      if (neighbor.data.type === 3) {
        this.goldFound = true;
        this.goldPos = {level: neighbor.data.level};
      }
    }

    // If current cell has a block and we're not carrying, pick it up
    if (cell.type === 2 && !this.carrying) {
      this.carrying = true;
      return "pickup";
    }

    // If we're carrying and at gold location, build up if needed
    if (this.carrying && cell.type === 3 && cell.level < 8) {
      this.carrying = false;
      return "drop";
    }

    // Movement helper
    const canMove = (neighborData) => {
      return neighborData.type !== 1 && 
             Math.abs(neighborData.level - cell.level) <= 1;
    };

    // Simple exploration strategy: prefer unblocked paths
    const validMoves = [];

    if (canMove(cell.left)) validMoves.push("left");
    if (canMove(cell.up)) validMoves.push("up");
    if (canMove(cell.right)) validMoves.push("right");
    if (canMove(cell.down)) validMoves.push("down");

    // If no valid moves and carrying, drop
    if (validMoves.length === 0 && this.carrying) {
      this.carrying = false;
      return "drop";
    }

    // If stuck, try any direction
    if (validMoves.length === 0) {
      return "right";
    }

    // Avoid going back to previous position if possible
    let bestMoves = validMoves.filter(move => {
      const opposite = {"left": "right", "right": "left", "up": "down", "down": "up"};
      return move !== opposite[this.lastMove];
    });

    if (bestMoves.length === 0) {
      bestMoves = validMoves;
    }

    // Prefer directions toward blocks or unexplored areas
    let priorityMove = null;
    for (let move of bestMoves) {
      const neighborData = cell[move];
      if (neighborData.type === 2) { // Block
        priorityMove = move;
        break;
      }
      if (neighborData.type === 3) { // Gold
        priorityMove = move;
        break;
      }
    }

    const chosenMove = priorityMove || bestMoves[this.moves % bestMoves.length];
    this.lastMove = chosenMove;

    return chosenMove;
  };
}
