      this.carrying = true;
      return "pickup";
    }

    if (this.carrying && cell.type === 3) {
      this.carrying = false;
      return "drop";
    }

    // Fast movement calculation
    const dirs = [];
    if (cell.left.type !== 1 && Math.abs(cell.left.level - cell.level) <= 1) {
      dirs.push({n: "left", d: cell.left});
    }
    if (cell.up.type !== 1 && Math.abs(cell.up.level - cell.level) <= 1) {
      dirs.push({n: "up", d: cell.up});
    }
    if (cell.right.type !== 1 && Math.abs(cell.right.level - cell.level) <= 1) {
      dirs.push({n: "right", d: cell.right});
